> **Note:**&#x20;
>
> Example Setup
>
> This example connects to an instance of MongoDB by using a
> connection URI. To learn more about connecting to your MongoDB
> instance, see the [Connect to MongoDB](node-connect) guide. This example
> also uses the `movies` collection in the `sample_mflix` database
> included in the [Atlas sample datasets](atlas/sample-data). You
> can load them into your database on the free tier of MongoDB Atlas by
> following the [MongoDB Get Started](get-started).The following full file example finds documents from the `movies` collection. It
uses the following parameters:* **Filter** that matches documents in which the `runtime` value is less than 15
  minutes.

* **Sort** that organizes returned documents in ascending order by
  title (alphabetical order in which "A" comes before "Z" and "1" before
  "9").

* **Projection** that explicitly excludes the `_id` field from
  returned documents and explicitly includes only the `title` and
  `imdb` object (and its embedded fields).**JavaScript:**JavaScript```javascript
import { MongoClient } from "mongodb";

// Replace the uri string with your MongoDB deployment's connection string.
const uri = "<connection string uri>";

const client = new MongoClient(uri);

async function run() {
  try {

    // Get the database and collection on which to run the operation
    const database = client.db("sample_mflix");
    const movies = database.collection("movies");

    // Query for movies that have a runtime less than 15 minutes
    const query = { runtime: { $lt: 15 } };
    const sortFields = { title: 1 };
    const projectFields = { _id: 0, title: 1, imdb: 1 };

    // Execute query 
    const cursor = movies.find(query).sort(sortFields).project(projectFields);

    // Print a message if no documents were found
    if ((await movies.countDocuments(query)) === 0) {
      console.log("No documents found!");
    }

    // Print returned documents
    for await (const doc of cursor) {
      console.dir(doc);
    }

  } finally {
    await client.close();
  }
}
run().catch(console.dir);

```**TypeScript:**TypeScript```typescript
import { MongoClient } from "mongodb";

// Replace the uri string with your MongoDB deployment's connection string.
const uri = "<connection string uri>";

const client = new MongoClient(uri);

type Minutes = number;

interface IMDB {
  rating: number;
  votes: number;
  id: number;
}

interface Movie {
  title: string;
  imdb: IMDB;
  runtime: Minutes;
}

async function run() {
  try {
    const database = client.db("sample_mflix");
    const movies = database.collection<Movie>("movies");

    const query = { runtime: { $lt: 15 } };
    const sortFields = { title: 1 };
    const projectFields = { _id: 0, title: 1, imdb: 1 };

    const cursor = movies.find<Movie>(query).sort(sortFields).project(projectFields);

    if ((await movies.countDocuments(query)) === 0) {
      console.warn("No documents found!");
    }

    for await (const doc of cursor) {
      console.dir(doc);
    } 
  } finally {
    await client.close();
  }
}
run().catch(console.dir);

```Running the preceding example results in the following output:```javascript
{ title: '10 Minutes', imdb: { rating: 7.9, votes: 743, id: 339976 } }
{ title: '3x3', imdb: { rating: 6.9, votes: 206, id: 1654725 } }
{ title: '7:35 in the Morning', imdb: { rating: 7.3, votes: 1555, id: 406501 } }
{ title: '8', imdb: { rating: 7.8, votes: 883, id: 1592502 } }
...
```> **Note:** You must chain a cursor method such as `sort()`, `limit()`,
> `skip()`, or `project()` to a read operation before iterating the cursor.
> If you specify a cursor method after iterating the cursor, the setting does
> not apply to the read operation.

